#include <stdio.h>

int main() {
    int n, i;
    int qtd_sim = 0, qtd_nao = 0;
    int total_feminino = 0, total_masculino = 0;
    int feminino_sim = 0, masculino_nao = 0;
    char sexo, resposta;

    printf("Digite a quantidade de pessoas: ");
    scanf("%d", &n);

    if (n <= 0) {
        printf("Quantidade invalida.\n");
        return 0;
    }

    for (i = 1; i <= n; i++) {
        do {
            printf("Pessoa %d - sexo (M/F): ", i);
            scanf(" %c", &sexo);
            if (sexo >= 'a' && sexo <= 'z') {
                sexo -= 32;
            }
        } while (sexo != 'M' && sexo != 'F');

        do {
            printf("Pessoa %d - resposta (S/N): ", i);
            scanf(" %c", &resposta);
            if (resposta >= 'a' && resposta <= 'z') {
                resposta -= 32;
            }
        } while (resposta != 'S' && resposta != 'N');

        if (resposta == 'S') {
            qtd_sim++;
        } else {
            qtd_nao++;
        }

        if (sexo == 'F') {
            total_feminino++;
            if (resposta == 'S') {
                feminino_sim++;
            }
        } else {
            total_masculino++;
            if (resposta == 'N') {
                masculino_nao++;
            }
        }
    }

    printf("\nNumero de pessoas que responderam sim: %d\n", qtd_sim);
    printf("Numero de pessoas que responderam nao: %d\n", qtd_nao);

    if (total_feminino > 0) {
        printf("Percentual de mulheres que responderam sim: %.2f%%\n", (feminino_sim * 100.0) / total_feminino);
    } else {
        printf("Percentual de mulheres que responderam sim: 0.00%%\n");
    }

    if (total_masculino > 0) {
        printf("Percentual de homens que responderam nao: %.2f%%\n", (masculino_nao * 100.0) / total_masculino);
    } else {
        printf("Percentual de homens que responderam nao: 0.00%%\n");
    }

    return 0;
}


